import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const configPath = path.join(__dirname, '../public/config/security-config.json');
const outputPath = path.join(__dirname, '../src/config/security-config.ts');

try {
  const config = JSON.parse(fs.readFileSync(configPath, 'utf8'));
  const debugProtection = config.debugProtection || {};

  const content = `// Auto-generated security configuration
// This file is generated by scripts/generate-security-config.js
// Do not edit this file directly

export const securityConfig = {
  debugProtection: {
    enabled: ${debugProtection.enabled !== false},
    disableF12: ${debugProtection.disableF12 !== false},
    disableDevToolsShortcuts: ${debugProtection.disableDevToolsShortcuts !== false},
    disableViewSource: ${debugProtection.disableViewSource !== false},
    disableContextMenu: ${debugProtection.disableContextMenu !== false},
    disableDrag: ${debugProtection.disableDrag !== false},
    disableSelect: ${debugProtection.disableSelect !== false},
    detectDevTools: ${debugProtection.detectDevTools !== false}
  }
} as const;
`;

  fs.writeFileSync(outputPath, content);
  console.log('✓ Generated security configuration');
} catch (error) {
  console.error('✗ Failed to generate security configuration:', error.message);
  process.exit(1);
}
